      "mainEntity": [
        {
          "@type": "Question",
          "name": "Is TCS applicable on the GST amount?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "No. TCS under Section 52 is collected at 0.5 percent in total, made up of 0.25 percent CGST and 0.25 percent SGST, on the net taxable value of supplies and not on the GST charged. On a Rs 1,00,000 taxable order the operator collects Rs 500, calculated on the taxable value rather than the Rs 1,18,000 invoice total."
          }
        },
        {
          "@type": "Question",
          "name": "What are the provisions of Sections 51 and 52 of the GST Act?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Section 51 is TDS, deducted at 2 percent by government departments and notified bodies on contracts above Rs 2,50,000 and reported in Form GSTR-7. Section 52 is TCS, collected at 0.5 percent by an e-commerce operator on the net value of supplies made through its platform and reported in Form GSTR-8. Both amounts reach the supplier's electronic cash ledger."
          }
        },
        {
          "@type": "Question",
          "name": "How does a seller claim credit for GST TCS collected by an operator?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "The operator files Form GSTR-8 by the 10th of the following month, and the amount then appears in the seller's TCS and TDS credit statement on the GST portal. Accepting that statement moves the credit into the electronic cash ledger, where it can be set against the GSTR-3B liability or claimed as a refund. Unaccepted entries stay unusable."
          }
        }
